import { Router } from 'express';
import { getDemoUser, getMe, updateProfile, getPatients, deleteAccount } from '../controllers/userController.js';
import { requireAuth } from '../middleware/auth.js';

const router = Router();
router.get('/demo', getDemoUser);
router.get('/me', requireAuth, getMe);
router.post('/profile', requireAuth, updateProfile);
router.get('/patients', requireAuth, getPatients);
router.delete('/me', requireAuth, deleteAccount);
export default router;
